// 1. Get the incoming data from the Loop Fixer node
const items = $input.all();

// 2. Map through all 10 data items without dropping any
const scoredLeads = items.map(item => {
  const root = item.json;

  // Dynamic Check: Handle zipped structure from the Loop Fixer or direct node input safely
  const formData = root.form_data || root;
  const crmData = root.crm_match || {};

  // Extract fields cleanly, prioritizing CRM data if a match exists, otherwise falling back to Form Data
  const rawEmail = formData["Email"] || crmData.email || "";
  const companyWebsite = crmData.website || formData["Domain"] || "unknown.com";
  const city = crmData.address?.city || "Unknown";

  // Establish base scoring metrics
  let leadScore = 50; // Everyone starts at 50 points
  let tier = "Tier 2 (Mid-Market)";

  // RULE 1: Check for high-value enterprise domains
  if (companyWebsite.includes('.org') || companyWebsite.includes('.net') || companyWebsite.includes('enterprise')) {
    leadScore += 35; // Major enterprise target bonus
  }

  // RULE 2: Filter out generic/spam emails
  if (rawEmail.toLowerCase().includes('gmail') || rawEmail.toLowerCase().includes('yahoo')) {
    leadScore -= 40; 
  }

  // RULE 3: Add bonus based on geographic parameters 
  if (city !== "Unknown") {
    leadScore += 10;
  }

  // 3. Categorize the lead into a final Tier based on total score
  if (leadScore >= 80) {
    tier = "Tier 1 (Enterprise)";
  } else if (leadScore < 40) {
    tier = "Tier 3 (Low Priority/Nurture)";
  }

  // 4. Return the enriched object, preserving the structural blocks for downstream routers
  return {
    json: {
      ...root, // CRITICAL: Keeps form_data and crm_match intact so Duplicate Detector still works!
      lead_info: {
        first_name: formData["First Name"] || "",
        last_name: formData["Last Name"] || "",
        email: rawEmail,
        company_domain: companyWebsite,
        city: city
      },
      scoring_metrics: {
        final_score: leadScore,
        assigned_tier: tier,
        processed_at: new Date().toISOString()
      }
    }
  };
});

return scoredLeads;

